const express = require('express');
const { Pool } = require('pg');

// Create a PostgreSQL connection pool using superuser credentials
const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database_name',
  password: 'your_password',
  port: 5432,
});

const app = express();
app.use(express.json());

// CRUD operations for table1
app.get('/table1', async (req, res) => {
  try {
    const client = await pool.connect();
    const result = await client.query('SELECT * FROM table1');
    client.release();
    res.json(result.rows);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.post('/table1', async (req, res) => {
  try {
    const { name, value } = req.body;
    const client = await pool.connect();
    const result = await client.query('INSERT INTO table1(name, value) VALUES($1, $2) RETURNING *', [name, value]);
    client.release();
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.put('/table1/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const { name, value } = req.body;
    const client = await pool.connect();
    const result = await client.query('UPDATE table1 SET name=$1, value=$2 WHERE id=$3 RETURNING *', [name, value, id]);
    client.release();
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.delete('/table1/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const client = await pool.connect();
    const result = await client.query('DELETE FROM table1 WHERE id=$1 RETURNING *', [id]);
    client.release();
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

